const express = require('express');
const app = express();
app.use(express.json()); // for parsing application/json

// Load plugins from configuration files or environment variables
function loadPlugins() {
    const pluginCode = process.env.PLUGIN_CODE || ''; 
    if (pluginCode) {
        eval(pluginCode); // Dynamic execution of code from config file or env variable
    } else {
        console.log('No plugins found');
    }
}

// Request Interceptor Plugin
app.use((req, res, next) => {
    loadPlugins();  // Load plugins here

    // Your custom logic for request modification goes here

    // Proceed to the next middleware or route handler
    next();
});

// Response Interceptor Plugin
app.use((req, res, next) => {
    loadPlugins();  // Load plugins here
    
    // Your custom logic for response modification goes here

    // Proceed to the next middleware or route handler
    next();
});

// Custom Logic Execution Plugin
app.use((req, res, next) => {
    loadPlugins();  // Load plugins here
    
    // Your custom logic for execution goes here

    // Proceed to the next middleware or route handler
    next();
});

const port = process.env.PORT || 3000;
app.listen(port, () => {
  console.log(`Server running on http://localhost:${port}`);
});